head.script:
/**
 * 화 면 명 : Export Customer Booking
 * 메뉴경로 : 국제물류/Air/Air Export/
 * ASIS경로 : /dongwon-debis-engine/src/main/webapp/il/airout/aobk/ar_101_01_01b.jsp
 * 작 성 자 : 박원
 * 작 업 일 : 2026-03-16
 * 작업내용 :
 *    1. 화면세팅
 *    2. 초기세팅(UDC), 그리드(데이터리스트)
 *    3. 스크립트 TOBE전환
 *    4. 기능확인(버튼)
 * 참고사항

 * 수정이력 :
 *    - 2026-03-16      박원    최초작성
 *    - 2026-04-10      이진우  T-6565 조치완료(Export Customer Booking_데이터 결함),scwin.timeFormatter추가
 */
/*
f_delete 
ds_CustomerBookingInfo.DeleteMarked();
행삭제 처리된 행 정상 삭제 되는지 확인필요

test data : ABK06060086
*/

scwin.cvsslMgntNo = "";
scwin.p_kcomcd    = "";
scwin.p_srno      = "";

scwin.lobranCd = "";

scwin.userId = "";
scwin.p_lobranCd = "";
scwin.p_lobranNm = "";

scwin.processFlag = "";  // 처리 결과를 체크하는 Flag 	
scwin.actionFlag = "";
scwin.v_contractno = "";

scwin.hd_kcomcd = "DBEX";
scwin.hd_iogb = "O";

scwin.currow = "";

scwin.onpageload = function() {

    var params = $c.data.getParameter();

	scwin.cvsslMgntNo = params.cvsslMgntNo == null ? "" : params.cvsslMgntNo;
	scwin.p_kcomcd    = params.kcomcd;
	scwin.p_srno      = params.srno;

    let memJson = $c.data.getMemInfo();
    console.log(memJson);
    scwin.lobranCd = memJson.lobranCd;

	if (scwin.lobranCd == null ){        
        scwin.lobranCd = " ";
    }

    scwin.userId = memJson.userId;
    scwin.p_lobranCd = memJson.lobranCd;
    scwin.p_lobranNm = memJson.lobranNm;

    const codeOptions = [
        { grpCd : "SD101", compID : "gr_CargoPickupInfo:transCondCd"},
        { grpCd : "IL007", compID : "gr_CargoPickupInfo:carCondCd"},
    ];
    $c.data.setCommonCode(codeOptions);
};

scwin.onUdcCompleted = function() {
    $p.setTimeout(function() {
        udc_ilcomCode.hide();
        scwin.f_Set("INIT");
  		scwin.f_DefaultValue();
       	//ed_srno.focus();
       	btn_Create.focus();
       	scwin.processFlag = "None";
       	scwin.f_getParametrSetting(); // link처리
    }, {"delay":50});
};

//---------------------------------------------------------
// Parameter Setting
//---------------------------------------------------------
scwin.f_getParametrSetting = function (){
    var kcomcd = scwin.p_kcomcd;
    var srno   = scwin.p_srno;

    if (srno == null || srno == ''){
        return false;
    }

    scwin.hd_kcomcd = kcomcd;
    ed_srno.setValue(srno);

    scwin.f_Retrieve();
}

//-------------------------------------------------------------------------
// 초기화
//-------------------------------------------------------------------------
scwin.f_DefaultValue = function () {
    ed_srno.setValue("");
    lc_blgb.setValue("H");
    lc_partialgb.setValue("N");
    rd_lngb.setValue("L");
    rd_lcsp.setValue("L");
    $c.gus.cfDisableObjects(lc_spType);
}

//---------------------------------------------------------
//화면세팅
//---------------------------------------------------------
scwin.f_Set = function (gubun) {
    switch (gubun) {    
        case "INIT" : //초기화
            $c.gus.cfDisableKeyData();
            $c.gus.cfDisableBtnOnly([btn_AddRow, btn_DeleteRow, btn_UndoRow,btn_OrderSend,btn_OrderSendDel]);
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_Find, btn_HouseLink]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Clear]);
            scwin.f_DisablePopUpObj();
            gr_CargoPickupInfo.setReadOnly ("grid", true);
            //$c.gus.cfEnableObjects(ed_srno);
            rd_lngb.setDisabled(true);
            ed_srno.setReadOnly(false);
            break;
        case "RETRIEVE" :  //조회모드	
            $c.gus.cfDisableKeyData();
            scwin.f_DisablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel]);
            $c.gus.cfDisableBtnOnly([btn_AddRow, btn_DeleteRow, btn_UndoRow,btn_OrderSend,btn_OrderSendDel]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_Clear]); 

            $c.gus.cfEnableBtnOnly([btn_Find, btn_HouseLink]);
            //$c.gus.cfEnableObjects(ed_srno);
            rd_lngb.setDisabled(true);
            ed_srno.setReadOnly(false);
            break;
        case "CREATE" : //신규
            $c.gus.cfEnableKeyData();
            scwin.f_EnablePopUpObj();
            $c.gus.cfDisableBtnOnly([btn_Create, btn_Update, btn_Delete, btn_Clear]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Cancel]);             	
            $c.gus.cfEnableBtnOnly([btn_AddRow, btn_DeleteRow, btn_UndoRow,btn_OrderSend,btn_OrderSendDel]);
            gr_CargoPickupInfo.setReadOnly ("grid", false);  
            //$c.gus.cfDisableObjects(ed_srno); 
            rd_lngb.setDisabled(false);
            ed_srno.setReadOnly(true);
            ds_ctrtNo.removeAll();      	
            break;
        case "UPDATE" :
            $c.gus.cfDisableBtnOnly([btn_Update, btn_Create, btn_Clear]);
            $c.gus.cfEnableBtnOnly([btn_Save, btn_Delete, btn_Cancel]);
            $c.gus.cfEnableBtnOnly([btn_AddRow, btn_DeleteRow, btn_UndoRow,btn_OrderSend,btn_OrderSendDel]);
            gr_CargoPickupInfo.setReadOnly ("grid", false);
            $c.gus.cfDisableKey();
            scwin.f_EnablePopUpObj();
            //$c.gus.cfDisableObjects(ed_srno);        
            rd_lngb.setDisabled(false);		
            ed_srno.setReadOnly(true);
            break;    
        case "SAVE" :
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_Clear]);
            $c.gus.cfEnableBtnOnly([btn_Update, btn_Create, btn_Delete,btn_OrderSend,btn_OrderSendDel]);
            scwin.f_Set("RETRIEVE");
            break;                
        case "DELETE" :
            $c.gus.cfDisableBtnOnly([btn_Save, btn_Cancel, btn_Clear]);
            $c.gus.cfEnableBtnOnly([btn_Create, btn_Update, btn_Delete,btn_OrderSend,btn_OrderSendDel]);
            scwin.f_Set("RETRIEVE");
            ds_CargoPickupInfo.removeAll();
            ds_CustomerBookingInfo.removeAll();
            break;                   
    }
}

//-------------------------------------------------------------------------
// PopUp 이미지를 활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_EnablePopUpObj = function () {
    $c.gus.cfEnableObjects([ica_ondt]);
    $c.gus.cfEnableObjects([btn_shcd, btn_ascd, btn_ipcd, btn_cncd, btn_ntcd, btn_pncd]); 
    $c.gus.cfEnableObjects([btn_dscd, btn_pncd, btn_pacd, btn_itcd, btn_whcd, btn_sacd]);
}

//-------------------------------------------------------------------------
// PopUp 이미지를 비활성화 시킨다. 
//-------------------------------------------------------------------------
scwin.f_DisablePopUpObj = function () {
    $c.gus.cfDisableObjects([ica_ondt]);
    $c.gus.cfDisableObjects([btn_shcd, btn_ascd, btn_ipcd, btn_cncd, btn_ntcd, btn_pncd]); 
    $c.gus.cfDisableObjects([btn_dscd, btn_pncd, btn_pacd, btn_itcd, btn_whcd, btn_sacd]);
}  

//-------------------------------------------------------------------------
//조회조건 바인딩
//-------------------------------------------------------------------------
scwin.f_ProcessBinding = async  function ( ds, gubun ) {  
    switch ( gubun ) {
        case "CustomerBookingSearch" :
            //ds.removeAll();
            //ds.AddRow();  				
            ds.set("kcomcd", scwin.hd_kcomcd);
            ds.set("srno", ed_srno.getValue().trim());
            ds.set("iogb", scwin.hd_iogb);
            break;						
        case "CustomerBookingSave" :
            ds.setCellData(ds.getRowPosition(), "kcomcd", scwin.hd_kcomcd);
            ds.setCellData(ds.getRowPosition(), "iogb", scwin.hd_iogb);
            break;
        case "ContractSearch" :
            //ds.removeAll();
            //ds.AddRow();
            ds.set("ctrtNo", scwin.v_contractno);
            ds.set("ctrtClntNo", ed_shcd.getValue().trim());
            ds.set("ctrtDtYn", "1");	
            ds.set("bizDomInatYn", "1");
            ds.set("ctrtDistrictCd", "ZZB"); // ZZA : 해운권역 , ZZB : 항공권역 
            ds.set("impExpDomesticClsCd", "O");   // I:Inbound , O:Outbound
            ds.set("scDate", ica_ondt.getValue().trim()); //적용 기간		

            break;	
        default:
            break;													
    }  //end switch
}  

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.f_Retrieve = async  function () {  
    scwin.actionFlag = "Retrieve";
    if (ed_srno.getValue().trim() == ""){
        //$c.win.alert(E_MSG_CM_ERR_002, ["Booking No"]);  //필수 입력 항목 입니다. 	
        $c.win.alert("Booking No is mandatory.");
        ed_srno.focus();		
        return false;
    }
    ds_CustomerBookingInfo.removeAll();
    ds_CargoPickupInfo.removeAll();  	 
    await scwin.f_ProcessBinding( dma_CustomerBookingSearch, "CustomerBookingSearch" );
    //tr_Retrieve.Post();		
    $c.sbm.execute(sbm_Retrieve);
}

//-------------------------------------------------------------------------
//조회 결과
//-------------------------------------------------------------------------	
scwin.f_ProcessResult = function (gubun){
    switch (gubun){
        case "NotExistBookingInfo" :
            scwin.f_Set("INIT");
            ds_CargoPickupInfo.removeAll();
            //cfAlertMsg(E_MSG_CM_ERR_049, [ed_srno.getValue()]);  //@이(가) 존재하지 않습니다.
            $c.win.alert(ed_srno.getValue() + " does not exist.");
            ed_srno.focus();
            break;
        case "ExistBookingInfo" :
        ds_CustomerBookingInfo.setRowPosition(0);
        //ds_CargoPickupInfo.setRowPosition(0);
            scwin.v_contractno = ds_CustomerBookingInfo.getCellData(ds_CustomerBookingInfo.getRowPosition(), "contractno");
            scwin.f_Set("RETRIEVE");
            scwin.f_ContractInfo();
            ed_srno.focus();
            break;	
        case "DeleteAction" :
            if (ds_CustomerBookingInfo.getRowCount() == 0){
                ds_CargoPickupInfo.removeAll();
            }				
            break;	
        default :
            break;
    }
}

//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.f_Cancel = function (){
    scwin.actionFlag = "Cancel";
    if (scwin.processFlag == "Create") {
        scwin.f_Set("INIT");  
        scwin.processFlag = "None";		
    } else {
        scwin.f_Set("RETRIEVE");  		
    }
    ds_CustomerBookingInfo.undoAll();
    //ds_CustomerBookingInfo.setJSON(ds_CustomerBookingInfo_Bak.getAllJSON(), false);
    //ds_CustomerBookingInfo.setRowPosition(0);
    ds_CargoPickupInfo.undoAll();
    //ds_CargoPickupInfo.setJSON(ds_CargoPickupInfo_Bak.getAllJSON(), false);

    ed_pkgs.setValue("");
    ed_innerPkg.setValue("");
    ed_wght.setValue("");
}

//-------------------------------------------------------------------------
// 신규
//-------------------------------------------------------------------------
scwin.f_Create = function (){
    scwin.actionFlag = "Create";
    //ds_CustomerBookingInfo_Bak.setJSON(ds_CustomerBookingInfo.getAllJSON(), false);
    ds_CustomerBookingInfo.removeAll();
    //ds_CargoPickupInfo_Bak.setJSON(ds_CargoPickupInfo.getAllJSON(), false);
    ds_CargoPickupInfo.removeAll();
    ds_CustomerBookingInfo.insertRow();
    ds_CustomerBookingInfo.setRowPosition(0);
    scwin.f_DefaultValue();	    
    scwin.f_Set("CREATE");  
    scwin.processFlag = "Create";
    ed_pkgs.setValue(0);
    ed_innerPkg.setValue(0);
    ed_wght.setValue(0);
    lc_blgb.focus();
}

//-------------------------------------------------------------------------
// 수정
//-------------------------------------------------------------------------
scwin.f_Update = function (){
    scwin.actionFlag = "Update";
    scwin.f_Set("UPDATE");
}

//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.f_Save = async function (){
    if((ds_CustomerBookingInfo.getModifiedIndex().length > 0) || (ds_CargoPickupInfo.getModifiedIndex().length > 0)){
        await scwin.f_ProcessBinding(ds_CustomerBookingInfo, "CustomerBookingSave");	           
        if (await scwin.f_ReqFieldChk()) {
            scwin.actionFlag = "Save";
            scwin.processFlag = "Save";

            //tr_Save.Post();
            var ipcd = ds_CustomerBookingInfo.getCellData(0, "ipcd");
            if(ipcd.length > 2){
                ds_CustomerBookingInfo.setCellData(0, "ipcd", ipcd.substring(0,2));
            }
            for(var i=0; i < ds_CargoPickupInfo.getRowCount(); i++) {
                var fromDistrictCd = ds_CargoPickupInfo.getCellData(i, "fromDistrictCd");
                var toDistrictCd = ds_CargoPickupInfo.getCellData(i, "toDistrictCd");

                if(fromDistrictCd.length >3){
                    ds_CargoPickupInfo.setEventPause("", true);
                    ds_CargoPickupInfo.setCellData(i, "fromDistrictCd", fromDistrictCd.substring(0,3));
                    ds_CargoPickupInfo.setEventPause("", false);
                }
                if(toDistrictCd.length >3){
                    ds_CargoPickupInfo.setEventPause("", true);
                    ds_CargoPickupInfo.setCellData(i, "toDistrictCd", toDistrictCd.substring(0,3));
                    ds_CargoPickupInfo.setEventPause("", false);
                }
            }

            $c.sbm.execute(sbm_Save);
            //scwin.f_Set("SAVE");
        }
    }else{
        //cfAlertMsg(E_MSG_CM_ERR_001, ["Customer Booking Info"]);  //@은(는) 변경된 사항이 없습니다.
        $c.win.alert("There have been no changes for Customer Booking Info");
    }
}

//유효성검사
scwin.f_ReqFieldChk = async function (){
    if (ica_ondt.getValue() == "") {
        //cfAlertMsg(E_MSG_CM_ERR_002, ["Onboard Date"]);
        $c.win.alert("Onboard Date is mandatory.");
        ica_ondt.focus();     	
        return false;
    }

    // Contract No Null Check
    if(lc_contractNo.getValue() == "") {
        //cfAlertMsg(E_MSG_CM_ERR_002, ["Contract No"]); //@는 필수입력항목입니다.
        $c.win.alert("Contract No is mandatory.");		
        lc_contractNo.focus();
        return false;
    }

    var chk = await $c.gus.cfValidate([gr_CargoPickupInfo]);
    var chk2 = await $c.gus.cfValidate([ica_ondt]);
    var chk3 = await $c.gus.cfValidate([lc_contractNo]);
    if (!chk || !chk2 || !chk3) {
        return false;
    }

    return true;
}

//-------------------------------------------------------------------------
// 삭제
//-------------------------------------------------------------------------
scwin.f_Delete = async function (){  
    //send date  check
    var checked = 0;
    var errorChk = 0;
    for ( var i = 0; i < ds_CargoPickupInfo.getRowCount(); i++) { 		    
        if (ds_CargoPickupInfo.getCellData(i, "sendDt") != "") {	    
            $c.win.alert("Order sended : Order No -> " + ds_CargoPickupInfo.getCellData(i, "srno")+ ",Seq -> " + ds_CargoPickupInfo.getCellData(i, "seq"));	  
            errorChk = 1;
        }		
        checked++;
    }
    if (errorChk == "1" ) {
        return;
    }

    if (ed_blno.getValue().trim() != ""){
        //cfAlertMsg(MSG_LO_WRN_001, [ed_blno.Text]);  //B/L No. @ 이(가) 생성되어  삭제 불가능 합니다.
        $c.win.alert("B/L No. " + ed_blno.getValue() + " 이(가) 생성되어  삭제 불가능 합니다.");
        ed_blno.focus();
        return false;
    }
    var chk = await $c.win.confirm(E_MSG_CM_CRM_004);
    if (chk){ //삭제 하시겠습니까? 
        //ds_CustomerBookingInfo.DeleteMarked();

        scwin.processFlag = "Delete";
        //tr_Save.Post();
        ds_CustomerBookingInfo.modifyRowStatus(0, "D");
        $c.sbm.execute(sbm_Save);

        /*
        scwin.f_Set("INIT");
        ed_srno.setValue("");
        ed_srno.focus();
        */
    }
}

//---------------------------------------------------------
//Order Send
//--------------------------------------------------------- 
scwin.f_orderSend = function () { 
    if (ds_CargoPickupInfo.getCellData(ds_CargoPickupInfo.getRowPosition(), "internalTyp")== "Y" ) {	 		
        // door order qty시 필수. 
        if(ed_itcd.getValue() == ""){
            //cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]); //@는 필수입력항목입니다.
            $c.win.alert("Item is mandatory.");
            ed_itcd.focus();
            return ;
        }

        var checked = 0;
        var errorChk = 0; 

        // chk not check
        var j = 0;
        for ( var i = 0; i < ds_CargoPickupInfo.getRowCount(); i++) {
            if (ds_CargoPickupInfo.getCellData(i, "chk") == "T") {	    
                j = j + 1;
            }			
        checked++;
        }
        if (j == 0 ) {
            errorChk = 1;	 // chk를 선택안함.
        }

        if (errorChk == "0" ) { //error가 없으면
            // order sended 실행.
            var checked = 0; 	
            for ( var i = 0; i < ds_CargoPickupInfo.getRowCount(); i++) {
                if (ds_CargoPickupInfo.getCellData(i, "chk") == "T") {	      
                    ds_CargoPickupInfo.setCellData(i, "kcomcd", scwin.hd_kcomcd);	
                    if (ds_CargoPickupInfo.getCellData(i, "sendDt") == "") {			    		    			    
                        ds_CargoPickupInfo.setCellData(i, "orderType", 1); // Order Send	
                    } else {
                        ds_CargoPickupInfo.setCellData(i, "orderType", 2); // Order Send
                    }
                    ds_CargoPickupInfo.setCellData(i, "inpid", scwin.userId);	

                }			
            checked++;
            } 	

            //tr_saveOrderSend.Post();  	
            $c.sbm.execute(sbm_saveOrderSend);
            //f_Retrieve();	    			
        }

    } else {
        $c.win.alert("Normal Type");
        return;
    }	
}

//---------------------------------------------------------
//Order Send Delete
//--------------------------------------------------------- 
scwin.f_orderSendDel = function () {
    if (ds_CargoPickupInfo.getCellData(ds_CargoPickupInfo.getRowPosition(), "internalTyp") == "Y" ) {		
        // order sended check
        var checked = 0;
        var errorChk = 0;  

        // chk not check
        var j = 0;
        for ( var i = 0; i < ds_CargoPickupInfo.getRowCount(); i++) {
            if (ds_CargoPickupInfo.getCellData(i, "chk") == "T") {	    
                j = j + 1;
            }			
            checked++;
        }
        if (j == 0 ) {
            errorChk = 1;	 // chk를 선택안함.
        }


        //send date  check
        var j = 0;
        for ( var i = 0; i < ds_CargoPickupInfo.getRowCount(); i++) {
            if (ds_CargoPickupInfo.getCellData(i, "chk") == "T") {	 		    
                if (ds_CargoPickupInfo.getCellData(i, "sendDt") == "") {	    
                    $c.win.alert("Order is not sended : Order No -> " + ds_CargoPickupInfo.getCellData(i, "srno")+ ",Seq -> " + ds_CargoPickupInfo.getCellData(i, "seq"));	  
                    errorChk = 1;
                }	
            }		
            checked++;
        }

        for ( var i = 0; i < ds_CargoPickupInfo.getRowCount(); i++) {
            if (ds_CargoPickupInfo.getCellData(i, "chk") == "T") {	    
                if (ds_CargoPickupInfo.getCellData(i, "mcomOdrNo") != "") {
                    $c.win.alert("Order sended : Order No -> " + ds_CargoPickupInfo.getCellData(i, "srno")+ ",Seq -> " + ds_CargoPickupInfo.getCellData(i, "seq"));	  
                    errorChk = 1;				    
                }
            }			
            checked++;
        } 

        if (errorChk == "0" ) { //error가 없으면
            // order sended 실행.
            var checked = 0; 	
            for ( var i = 0; i < ds_CargoPickupInfo.getRowCount(); i++) {
                if (ds_CargoPickupInfo.getCellData(i, "chk") == "T") {	      
                    ds_CargoPickupInfo.setCellData(i, "kcomcd", scwin.hd_kcomcd);
                    ds_CargoPickupInfo.setCellData(i, "orderType", 3); // Order Send	Del
                    ds_CargoPickupInfo.setCellData(i, "inpid", scwin.userId);
                }			
                checked++;
            } 	
            //tr_saveOrderSend.Post();
            $c.sbm.execute(sbm_saveOrderSend);
            //f_Retrieve();
        }
    } else {
        $c.win.alert("Normal Type");
        return;		
    }
}   

//행추가
scwin.f_AddRow = function () {
    if (ed_srno.getValue() == "" ){ 
        //cfAlertMsg(E_MSG_CM_ERR_002, ["Booking Header"]);  // @은(는) 필수 입력 항목입니다.
        $c.win.alert("Booking Header is mandatory.");
    } else if (ed_itcd.getValue() == "") {
        //cfAlertMsg(E_MSG_CM_ERR_002, ["Item"]);  // @은(는) 필수 입력 항목입니다.
        $c.win.alert("Item is mandatory.");
    }else{
        ds_CargoPickupInfo.insertRow();
        gr_CargoPickupInfo.setFocusedCell(ds_CargoPickupInfo.getRowCount()-1,0);

        ds_CargoPickupInfo.setCellData(ds_CargoPickupInfo.getRowPosition(),"kcomcd", scwin.hd_kcomcd);
        ds_CargoPickupInfo.setCellData(ds_CargoPickupInfo.getRowPosition(),"srno", ed_srno.getValue());
        ds_CargoPickupInfo.setCellData(ds_CargoPickupInfo.getRowPosition(), "internalTyp", "N");
        ds_CargoPickupInfo.setCellData(ds_CargoPickupInfo.getRowPosition(), "transCondCd", "1");

        //Focus 이동
        //gr_CargoPickupInfo.setColumn("doorDt");
        gr_CargoPickupInfo.setFocusedCell(ds_CargoPickupInfo.getRowCount()-1,"doorDt");
    }
}

//-------------------------------------------------------------------------
// function name : f_DelRow
// function desc : 그리드  행삭제
//-------------------------------------------------------------------------
scwin.f_DeleteRow = function (){

    if (ds_CargoPickupInfo.getCellData(ds_CargoPickupInfo.getRowPosition(), "sendDt") != "") {
        //cfAlertMsg(E_MSG_CM_ERR_041, ["Order sended","delete"]);  // @은(는) @할 수 없습니다.
        $c.win.alert("Order sended operation cannot be performed for delete.");
    } else {
        //ds_CargoPickupInfo.DeleteMarked();
        if(ds_CargoPickupInfo.getRowStatus(ds_CargoPickupInfo.getRowPosition()) == "C"){
            ds_CargoPickupInfo.removeRow(ds_CargoPickupInfo.getRowPosition());
        } else {
            ds_CargoPickupInfo.deleteRow(ds_CargoPickupInfo.getRowPosition());
        }
    }		  
}  	

//행취소
scwin.f_UndoRow = function () {
    //ds_CargoPickupInfo.UndoMarked();
    if(ds_CargoPickupInfo.getRowStatus(ds_CargoPickupInfo.getRowPosition()) == "C"){
        ds_CargoPickupInfo.removeRow(ds_CargoPickupInfo.getRowPosition());
    } else {
        ds_CargoPickupInfo.undoRow(ds_CargoPickupInfo.getRowPosition());
    }
}


