scwin.f_OpenCommonPopUp = function (gubun1, pWinCloseTF, pAllSearchTF, pNoDataCloseTF) {
    var rtnList			= new Array();

    switch (gubun1) {	
        case "Warehouse" :  //Warehouse
            udc_whcd.ilCommonPopUp(scwin.callbackAirBoneZoneCode	    // XML상의 SELECT ID	
