                //cfSetReturnValue(rtnList, ed_whcd, ed_whnm);
            break;			
        case "Salesman" :  //Salesman
            udc_sacd.ilCommonPopUp(scwin.callbackEmpInfo
                                    ,ed_sacd.getValue().trim()
