                                    ,pWinCloseTF
                                    ,'2'
                                    ,"Code, Name"
                                    ,'80,230'
                                    ,"3,4,5,6,7,8,9,10"
                                    ,null ,null ,null ,null ,null ,null
                                    ,pAllSearchTF
                                    ,"Salesman,Code,Name"
                                    ,pNoDataCloseTF
                                    ); 

                //cfSetReturnValue(rtnList, ed_sacd, ed_sanm);
            break;	  			
        case "Item" :  //Item
            udc_itcd.ilCommonPopUp(scwin.callbackCommGoodsInfo
                                    ,ed_itcd.getValue().trim()
                                    ,ed_itnm.getValue()
                                    ,pWinCloseTF
                                    ,'2'
                                    ,"Code, Name"
