                                    ,ed_unit.getValue()					            
                                    ,pWinCloseTF
                                    ,'2'
                                    ,"Code, Name"
                                    ,'80,230'
                                    ,"3,4,5,6,7,8,9,10"
                                    ,'IL002' ,null ,null ,null ,null ,null
