scwin.f_OpenPgm = function (name){
    if(name=="Find"){
        var strPath = "/ui/il/airout/aobk/ar_101_01_02b.xml"; 

        var param = {
            iogb : "O"
        }
        //cfTabMenuUpdate( strPath , "Customer Booking Search");
        $c.win.openMenu("Customer Booking Search", strPath,"ar_101_01_02b.xml",param,{openAction : "exist"});

    }else if(name=="M_Booking"){
        /*
        var strPath = "/il/airout/aobk/ar_102_01_01b.jsp?kcomcd=" + scwin.hd_kcomcd +
                                                        "&linkType=MawbookingCreate" +
                                                        "&ondt=" + ica_ondt.getValue().trim() +
                                                        "&dscd=" + ed_dscd.getValue().trim() +
                                                        "&dsnm=" + txt_dsnm.getValue().trim() +
                                                        "&fltno=" + ed_fltno.getValue().trim()
                                                            ; 
        */
        var strPath = "/ui/il/airout/aobk/ar_102_01_01b.xml";

        var param = {
            kcomcd : scwin.hd_kcomcd,
            linkType : "MawbookingCreate",
            ondt : ica_ondt.getValue().trim(),
            dscd : ed_dscd.getValue().trim(),
            dsnm : ed_dsnm.getValue().trim(),
            fltno : ed_fltno.getValue().trim()
        }
        console.log(param);

        //cfTabMenuUpdate( strPath , "Master Booking");
        $c.win.openMenu("Master Booking", strPath,"ar_102_01_01b.xml",param,{openAction : "exist"});

    }else if(name=="House"){
        /*
        var strPath = "/il/airout/aobl/ar_104_01_01b.jsp?kcomcd=" + scwin.hd_kcomcd + 
                                                        "&blno=" + ed_blno.getValue();	  
        */
        var strPath = "/ui/il/airout/aobl/ar_104_01_01b.xml";

        var param = {
            kcomcd : scwin.hd_kcomcd,
            blno : ed_blno.getValue()
        }                                         
        //cfTabMenuUpdate( strPath , "Export House  B/L");
        $c.win.openMenu("Export House  B/L", strPath,"ar_104_01_01b.xml",param,{openAction : "exist"});
    }
}

