scwin.f_ContractInfo = async function (gubun) {  
    if ((scwin.actionFlag != "Retrieve") && (ed_shcd.getValue().trim() == "")){
        //cfAlertMsg(E_MSG_CM_ERR_002, ["Shipper Info"]);  //필수 입력 항목 입니다. 	
        $c.win.alert("Shipper Info is mandatory.");
        ed_shcd.focus();		
        return false;
    }
    ds_ctrtNo.removeAll();	
    await scwin.f_ProcessBinding(dma_retrieveCtrtClnt, "ContractSearch");

    console.log("f_ContractInfo");
    if (gubun == "Actual") {
        dma_retrieveCtrtClnt.setCellData(dma_retrieveCtrtClnt.getRowPosition(), "ctrtClntNo", ed_ascd.getValue().trim());
    } 
    console.log("DT :" +ica_ondt.getValue());
    if (ica_ondt.getValue().trim() != ""){
        //tr_retrieveCtrtClnt.Post();
        $c.sbm.execute(sbm_retrieveCtrtClnt);
/*
        // sbm_retrieveCtrtClnt_submitDone 으로
        if (ds_ctrtNo.getRowCount() > 0 ) {
            if (ds_ctrtNo.getRowCount() == 1) {
                ds_ctrtNo.setRowPosition(0);
            } else {
                ds_ctrtNo.setRowPosition(1);
            }

            console.log("row P :" + ds_ctrtNo.getRowPosition());
            console.log(ds_ctrtNo.getRowPosition(),"empNo");
            ed_sacd.setValue(ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(),"empNo"));
            if (ed_sacd.getValue().trim() != ""){
                scwin.f_OpenCommonPopUp('Salesman','T','F','F');		
            }

        }
*/
    }
}




