scwin.sbm_Save_submitdone =  async function (e) {
    console.log(e.responseJSON.resultDataSet);
	//if (ds_ResultMsg.getCellData(ds_ResultMsg.getRowPosition(),"srno") != "") {
    if (ds_ResultMsg.getCellData(0,"srno") != "") {
        //console.log("ds_ResultMsg srno : "+ ds_ResultMsg.getCellData(0,"srno"));
    	await ed_srno.setValue(ds_ResultMsg.getCellData(0,"srno"));   
	}

    if(e.responseJSON.resultDataSet[0].Code == 0) {
        if(scwin.processFlag == "Delete") {
            scwin.f_ProcessResult("DeleteAction");
            await $c.win.alert(E_MSG_CM_INF_004);	// 성공적으로 삭제하였습니다
            scwin.f_Set("INIT");
            ed_srno.setValue("");
            ed_srno.focus();
            ds_CustomerBookingInfo.removeAll();
            ds_CargoPickupInfo.removeAll();
        } else {
            await $c.win.alert(E_MSG_CM_INF_001);	// 성공적으로 저장하였습니다 	
		    scwin.f_Retrieve();    	
            scwin.f_Set("SAVE");
        }
        scwin.processFlag = "None";
    }

};

scwin.sbm_saveOrderSend_submitdone = function (e) {
    if(e.responseJSON.resultDataSet[0].Code == 0) {
        $c.win.alert("Data was saved successfully");
        scwin.f_Retrieve();
    }
};

scwin.sbm_retrieveCtrtClnt_submitdone = function (e) {
    var options = {};
	options.sortIndex = "ctrtNo";
	options.sortOrder = "-1";     //오른차순:"1", 내림차순"-1"
	ds_ctrtNo.multisort(options);

    if (ds_ctrtNo.getRowCount() > 0 ) {
        if (ds_ctrtNo.getRowCount() == 1) {
            ds_ctrtNo.setRowPosition(0);
        } else {
            ds_ctrtNo.setRowPosition(1);
        }

        console.log("row P :" + ds_ctrtNo.getRowPosition());


        var empno = ds_ctrtNo.getCellData(ds_ctrtNo.getRowPosition(),"empNo");
        ed_sacd.setValue(empno);
        if(empno != null && empno != "") {
            ed_sanm.setValue("");
        }
        if (ed_sacd.getValue().trim() != ""){
            scwin.f_OpenCommonPopUp('Salesman','T','F','F');		
        }

    }
};

